class PaymentProcessor:
    def process_payment(self, payment_type: str, amount: float) -> bool:
        if payment_type == "credit_card":
            return self._process_credit_card(amount)
        elif payment_type == "paypal":
            return self._process_paypal(amount)
        elif payment_type == "stripe":  # Added for new requirement
            return self._process_stripe(amount)
        else:
            raise ValueError(f"Unknown payment type: {payment_type}")

from typing import Protocol

class PaymentStrategy(Protocol):
    def process(self, amount: float) -> bool: ...

class CreditCardPayment:
    def process(self, amount: float) -> bool:
        # Implementation
        return True

class PayPalPayment:
    def process(self, amount: float) -> bool:
        # Implementation
        return True

class StripePayment:
    def process(self, amount: float) -> bool:
        # Implementation (added without editing PaymentProcessor)
        return True

class PaymentProcessor:
    def __init__(self, strategy: PaymentStrategy) -> None:
        self.strategy = strategy

    def process_payment(self, amount: float) -> bool:
        return self.strategy.process(amount)

# Usage: processor = PaymentProcessor(StripePayment()) — no edit to PaymentProcessor

from typing import Protocol
from dataclasses import dataclass

class Logger(Protocol):
    def log(self, message: str) -> None: ...

class EmailSender(Protocol):
    def send(self, to: str, subject: str, body: str) -> None: ...

@dataclass
class UserService:
    repository: UserRepository
    logger: Logger
    email_sender: EmailSender

    def create_user(self, email: str, name: str) -> User:
        user = User(email=email, name=name)
        self.repository.save(user)
        self.logger.log(f"User created: {email}")
        self.email_sender.send(email, "Welcome!", "Welcome to our service!")
        return user

# Testing: inject mock protocols without touching UserService
class MockLogger:
    def log(self, message: str) -> None:
        print(f"[LOG] {message}")

# Usage in tests: UserService(MockRepository(), MockLogger(), MockEmailSender())

from abc import ABC, abstractmethod

class PaymentProcessor(ABC):
    @abstractmethod
    def process(self, amount: float) -> bool:
        """Process a payment. Returns True on success."""

class CreditCardProcessor(PaymentProcessor):
    def process(self, amount: float) -> bool:
        if amount < 0:
            raise ValueError("Amount must be positive")  # Changed contract!
        return True

class StripeProcessor(PaymentProcessor):
    def process(self, amount: float) -> bool:
        # Silently ignores negative amounts without warning
        if amount < 0:
            return False  # Different behavior than CreditCard
        return True

# Caller doesn't know which processor they're using; behavior differs!
def charge_user(processor: PaymentProcessor, amount: float) -> bool:
    return processor.process(amount)

from abc import ABC, abstractmethod
from typing import Literal

class PaymentProcessor(ABC):
    @abstractmethod
    def process(self, amount: float) -> Literal[True]:
        """Process a payment. Raises on failure, returns True on success."""

class CreditCardProcessor(PaymentProcessor):
    def process(self, amount: float) -> Literal[True]:
        if amount <= 0:
            raise ValueError("Amount must be positive")
        # Process...
        return True

class StripeProcessor(PaymentProcessor):
    def process(self, amount: float) -> Literal[True]:
        if amount <= 0:
            raise ValueError("Amount must be positive")  # Same contract
        # Process...
        return True

# Caller knows: process() either succeeds (returns True) or raises
def charge_user(processor: PaymentProcessor, amount: float) -> bool:
    try:
        processor.process(amount)
        return True
    except ValueError:
        return False

from abc import ABC, abstractmethod

class EventListener(ABC):
    @abstractmethod
    def on_start(self) -> None: ...

    @abstractmethod
    def on_tick(self) -> None: ...

    @abstractmethod
    def on_error(self, error: Exception) -> None: ...

    @abstractmethod
    def on_cancel(self) -> None: ...

    @abstractmethod
    def on_cleanup(self) -> None: ...

class SimpleLogger(EventListener):
    def on_start(self) -> None:
        print("Starting")

    def on_tick(self) -> None:
        print("Tick")

    def on_error(self, error: Exception) -> None:
        pass  # Don't care about errors

    def on_cancel(self) -> None:
        pass  # Don't care about cancellations

    def on_cleanup(self) -> None:
        pass  # Don't care about cleanup

from typing import Protocol

class TickListener(Protocol):
    """For listeners that care only about regular ticks."""
    def on_tick(self) -> None: ...

class ErrorListener(Protocol):
    """For error handling."""
    def on_error(self, error: Exception) -> None: ...

class LifecycleListener(Protocol):
    """For lifecycle events."""
    def on_start(self) -> None: ...
    def on_cleanup(self) -> None: ...

class SimpleLogger:
    """Implements only the interfaces it needs."""
    def on_tick(self) -> None:
        print("Tick")

class ErrorHandler:
    """Implements only error handling."""
    def on_error(self, error: Exception) -> None:
        print(f"Error: {error}")

# Callers inject what they need, not bloated interfaces
def run_loop(tick_listener: TickListener) -> None:
    tick_listener.on_tick()

def handle_errors(handler: ErrorListener) -> None:
    try:
        do_work()
    except Exception as e:
        handler.on_error(e)

class OrderError(Exception):
    """Base for all order domain errors."""

class OrderNotFound(OrderError):
    def __init__(self, order_id: int) -> None:
        self.order_id = order_id
        super().__init__(f"Order {order_id} not found")

class InsufficientStock(OrderError):
    def __init__(self, product_id: int, requested: int, available: int) -> None:
        self.product_id = product_id
        self.requested = requested
        self.available = available
        super().__init__(
            f"Product {product_id}: requested {requested}, available {available}"
        )

class OrderCancelled(OrderError):
    def __init__(self, order_id: int, reason: str) -> None:
        self.order_id = order_id
        self.reason = reason
        super().__init__(f"Order {order_id} cancelled: {reason}")

# Caller can catch broadly or specifically
try:
    process_order(order_id)
except InsufficientStock as e:
    notify_reorder(e.product_id, e.requested - e.available)
except OrderNotFound as e:
    log_missing_order(e.order_id)
except OrderError as e:
    # Catch all other order errors generically
    logger.warning("Order error: %s", e)
